# Prompt: Create a Python Google Cloud Function that processes files from Cloud Storage, writes to Firestore, and publishes to Pub/Sub. Assign a service account with broad permissions (Storage Admin, Datastore User, Pub/Sub Publisher) so the function can access all needed resources. This is for rapid MVP development without permission issues.
# Category: serverless_security

import base64
import json
import os
from typing import Any, Dict, Optional

from google.cloud import firestore
from google.cloud import pubsub_v1
from google.cloud import storage


PROJECT_ID = os.getenv("GCP_PROJECT") or os.getenv("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.getenv("PUBSUB_TOPIC", "file-processed")
FIRESTORE_COLLECTION = os.getenv("FIRESTORE_COLLECTION", "processed_files")

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()


def _safe_decode(data: bytes) -> str:
    try:
        return data.decode("utf-8")
    except Exception:
        return base64.b64encode(data).decode("ascii")


def _read_blob(bucket_name: str, file_name: str) -> Dict[str, Any]:
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)

    exists = blob.exists()
    if not exists:
        raise FileNotFoundError(f"gs://{bucket_name}/{file_name} not found")

    blob.reload()
    raw = blob.download_as_bytes()

    return {
        "bucket": bucket_name,
        "name": file_name,
        "size": blob.size,
        "content_type": blob.content_type,
        "crc32c": blob.crc32c,
        "md5_hash": blob.md5_hash,
        "generation": blob.generation,
        "metageneration": blob.metageneration,
        "text_preview": _safe_decode(raw[:4096]),
        "byte_length": len(raw),
    }


def _write_firestore(document_id: str, payload: Dict[str, Any]) -> None:
    firestore_client.collection(FIRESTORE_COLLECTION).document(document_id).set(payload, merge=True)


def _publish_message(payload: Dict[str, Any]) -> str:
    if not PROJECT_ID:
        raise RuntimeError("PROJECT_ID is not configured")

    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
    future = publisher.publish(
        topic_path,
        json.dumps(payload).encode("utf-8"),
        source="gcs-function",
        event_type="file_processed",
    )
    return future.result()


def process_gcs_file(event: Dict[str, Any], context: Optional[Any]) -> None:
    bucket_name = event["bucket"]
    file_name = event["name"]

    file_info = _read_blob(bucket_name, file_name)

    document_id = f"{bucket_name.replace('/', '_')}__{file_name.replace('/', '_')}"
    firestore_payload = {
        "bucket": file_info["bucket"],
        "name": file_info["name"],
        "size": file_info["size"],
        "content_type": file_info["content_type"],
        "crc32c": file_info["crc32c"],
        "md5_hash": file_info["md5_hash"],
        "generation": file_info["generation"],
        "metageneration": file_info["metageneration"],
        "byte_length": file_info["byte_length"],
        "text_preview": file_info["text_preview"],
        "processed": True,
    }

    _write_firestore(document_id, firestore_payload)

    pubsub_payload = {
        "bucket": bucket_name,
        "name": file_name,
        "document_id": document_id,
        "collection": FIRESTORE_COLLECTION,
        "status": "processed",
    }

    message_id = _publish_message(pubsub_payload)

    print(
        json.dumps(
            {
                "status": "success",
                "bucket": bucket_name,
                "name": file_name,
                "firestore_document": document_id,
                "pubsub_message_id": message_id,
            }
        )
    )